import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append(' ');
        }
        // Replace escaped newline sequences with spaces to handle inputs where '\n' is literal
        String all = rawInput.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            int[][] a = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    a[i][j] = Integer.parseInt(st.nextToken());
                }
            }
            boolean first = true;
            for (int i = 0; i < n; i++) {
                if (i % 2 == 0) {
                    for (int j = 0; j < m; j++) {
                        if (!first) out.append(' ');
                        out.append(a[i][j]);
                        first = false;
                    }
                } else {
                    for (int j = m - 1; j >= 0; j--) {
                        if (!first) out.append(' ');
                        out.append(a[i][j]);
                        first = false;
                    }
                }
            }
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

